class Solution:
    def minCapability(self, nums, k):
        """
        :type nums: List[int]
        :type k: int
        :rtype: int
        """
        def can_rob(capacity):
            # Can we rob k houses with max value <= capacity?
            count = 0
            i = 0
            while i < len(nums):
                if nums[i] <= capacity:
                    count += 1
                    i += 2  # Skip next house
                else:
                    i += 1
            return count >= k

        left, right = min(nums), max(nums)

        while left < right:
            mid = (left + right) // 2
            if can_rob(mid):
                right = mid
            else:
                left = mid + 1

        return left
